import{f as a,o as e,c as d,a2 as r}from"./chunks/framework.DHYrF-q6.js";const c=JSON.parse('{"title":"分布式 ID","description":"","frontmatter":{"title":"分布式 ID","outline":[2,3]},"headers":[],"relativePath":"middleware/distributed-system/id-generator.md","filePath":"middleware/distributed-system/id-generator.md","lastUpdated":1780747276000}'),i={name:"middleware/distributed-system/id-generator.md"};function l(s,t,n,o,h,p){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="分布式-id" tabindex="-1">分布式 ID <a class="header-anchor" href="#分布式-id" aria-label="Permalink to &quot;分布式 ID&quot;">​</a></h1><blockquote><p>内容完善中，此页面将持续更新。</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>在分布式系统中，经常需要生成全局唯一的 ID 来标识数据（如订单号、用户 ID、消息 ID 等）。由于分布式系统没有单点数据库的自增主键，需要专门的方案来生成全局唯一且有序的 ID。</p><h2 id="核心方案概览" tabindex="-1">核心方案概览 <a class="header-anchor" href="#核心方案概览" aria-label="Permalink to &quot;核心方案概览&quot;">​</a></h2><h3 id="uuid" tabindex="-1">UUID <a class="header-anchor" href="#uuid" aria-label="Permalink to &quot;UUID&quot;">​</a></h3><p>UUID（Universally Unique Identifier）是一种标准化的全局唯一标识符，通过随机数或机器信息生成 128 位的 ID。</p><p><strong>优点</strong>：</p><ul><li>生成简单，无需任何中心化协调</li><li>冲突概率极低（理论上可忽略）</li></ul><p><strong>缺点</strong>：</p><ul><li>无序，不适合作为数据库主键（B+树索引分裂严重）</li><li>占用空间大（36 字符 / 128 位）</li><li>不可读，不利于问题排查</li></ul><h3 id="雪花算法-snowflake" tabindex="-1">雪花算法（Snowflake） <a class="header-anchor" href="#雪花算法-snowflake" aria-label="Permalink to &quot;雪花算法（Snowflake）&quot;">​</a></h3><p>Twitter 开源的分布式 ID 生成算法，产生 64 位 Long 类型 ID，结构如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─┬─────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│0│ 41 位时间戳 (毫秒)  │ 10 位机器 ID  │ 12 位序列号 │</span></span>
<span class="line"><span>└─┴─────────────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>组成部分</th><th>位数</th><th>说明</th></tr></thead><tbody><tr><td><strong>符号位</strong></td><td>1 位</td><td>始终为 0，表示正数</td></tr><tr><td><strong>时间戳</strong></td><td>41 位</td><td>毫秒级时间戳，可使用约 69 年</td></tr><tr><td><strong>机器 ID</strong></td><td>10 位</td><td>可部署 1024 台机器</td></tr><tr><td><strong>序列号</strong></td><td>12 位</td><td>同一毫秒内可生成 4096 个 ID</td></tr></tbody></table><p><strong>优点</strong>：</p><ul><li>高性能（纯内存计算，单机可达数万 QPS）</li><li>趋势递增，适合数据库索引</li><li>可定制化（调整各段位数）</li></ul><p><strong>缺点</strong>：</p><ul><li>依赖机器时钟，时钟回拨会导致 ID 重复</li><li>机器 ID 需要手动分配或额外协调</li></ul><h3 id="数据库号段模式" tabindex="-1">数据库号段模式 <a class="header-anchor" href="#数据库号段模式" aria-label="Permalink to &quot;数据库号段模式&quot;">​</a></h3><p>利用数据库的自增能力或号段分配来生成 ID。常见实现：每次从数据库申请一批 ID 号段（如 1000 个），在本地内存中分配使用，用完后再次申请。</p><p><strong>优点</strong>：</p><ul><li>强依赖数据库，ID 分配可靠</li><li>趋势递增，适合数据库索引</li></ul><p><strong>缺点</strong>：</p><ul><li>数据库成为单点瓶颈</li><li>号段用尽时需重新申请，存在延迟</li></ul><h3 id="redis-生成" tabindex="-1">Redis 生成 <a class="header-anchor" href="#redis-生成" aria-label="Permalink to &quot;Redis 生成&quot;">​</a></h3><p>利用 Redis 的 <code>INCR</code> 或 <code>INCRBY</code> 命令原子递增生成 ID。</p><p><strong>优点</strong>：</p><ul><li>高性能（Redis 单机可达 10 万+ QPS）</li><li>天然递增</li></ul><p><strong>缺点</strong>：</p><ul><li>依赖 Redis 的高可用（需持久化 + 主从）</li><li>恢复后可能重复（需设置合适的初始值）</li></ul><h2 id="方案对比" tabindex="-1">方案对比 <a class="header-anchor" href="#方案对比" aria-label="Permalink to &quot;方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>性能</th><th>有序性</th><th>依赖性</th><th>复杂度</th></tr></thead><tbody><tr><td><strong>UUID</strong></td><td>极高</td><td>无序</td><td>无</td><td>低</td></tr><tr><td><strong>雪花算法</strong></td><td>高</td><td>趋势递增</td><td>依赖时钟</td><td>中</td></tr><tr><td><strong>数据库号段</strong></td><td>中</td><td>严格递增</td><td>依赖数据库</td><td>中</td></tr><tr><td><strong>Redis</strong></td><td>高</td><td>严格递增</td><td>依赖 Redis</td><td>中</td></tr></tbody></table><h2 id="选型考量" tabindex="-1">选型考量 <a class="header-anchor" href="#选型考量" aria-label="Permalink to &quot;选型考量&quot;">​</a></h2><p>选择分布式 ID 方案时，需要综合考虑以下因素：</p><ul><li><strong>是否需要有序</strong>：数据库主键通常需要有序 ID 以优化 B+树索引</li><li><strong>性能要求</strong>：ID 生成的 QPS 需求</li><li><strong>可用性要求</strong>：ID 生成服务是否允许短暂不可用</li><li><strong>运维复杂度</strong>：是否需要额外的中间件支持</li></ul><div class="info custom-block"><p class="custom-block-title">更多内容完善中</p><p>本文档将逐步补充各方案的详细实现原理、代码示例和面试题解析。敬请期待。</p></div>`,37)])])}const g=a(i,[["render",l]]);export{c as __pageData,g as default};
